module top_module(
    Y ,
    A1,
    A2,
    A3,
    B1
);output Y ;
    input  A1;
    input  A2;
    input  A3;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire [3:0] signal_inverted;
    assign signal_inverted = {A1, A2, A3, B1};

    assign Y = (signal_inverted == 4'b0000) ? 1'b0 :
               (signal_inverted == 4'b1111) ? 1'b1 :
               (signal_inverted != 4'b0000) ? 1'b1 :
               (signal_inverted != 4'b1111) ? 1'b0 :
               1'bx;

endmodule
